/**
 * InfraWeaver brand logo for transactional email — SERVER ONLY.
 *
 * The PNG is embedded (base64) and attached as an inline CID image rather than a
 * remote `<img src="https://…">`: CID inline images render in Gmail/Outlook without
 * the recipient having to "load remote images", and need no publicly-reachable
 * host (the console origin is internal). The Gmail sender AVATAR bubble is a
 * separate mechanism (BIMI DNS + the SVG in infra), not this in-body logo.
 *
 * Source asset: the real brand mark from the public repo (`images/logo.png`, the
 * neon woven-hex on black), processed to a 256×256 rounded app-badge (black tile,
 * transparent corners) — mirrored to `public/infraweaver-mark.png`. The dark badge
 * is deliberate: neon-on-black is the brand, and it reads as a crisp logo tile on
 * the light email card.
 */
import "server-only";
import type Mail from "nodemailer/lib/mailer";

/** Content-ID referenced by `<img src="cid:…">` in branded email bodies. */
export const INFRAWEAVER_LOGO_CID = "infraweaver-logo";

/** Base64 of the 256×256 brand badge PNG (black rounded tile, transparent corners). */
const INFRAWEAVER_LOGO_PNG_BASE64 =
  "";

/** The nodemailer inline attachment for the brand logo. */
export function logoAttachment(): Mail.Attachment {
  return {
    filename: "infraweaver.png",
    content: Buffer.from(INFRAWEAVER_LOGO_PNG_BASE64, "base64"),
    cid: INFRAWEAVER_LOGO_CID,
    contentType: "image/png",
  };
}

/** Brand palette — single source so every transactional mail reads as one system. */
const BRAND = {
  indigo: "#4f46e5",
  page: "#eef1f6",
  card: "#ffffff",
  border: "#e6e8ef",
  ink: "#0f172a",
  muted: "#64748b",
  faint: "#94a3b8",
  fontStack: "-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif",
} as const;

/**
 * Hidden preview text (the snippet a client shows next to the subject in the inbox
 * list). Rendered off-screen so it never appears in the body itself. The trailing
 * zero-width padding stops the client from bleeding following body text into the
 * preview.
 */
function preheader(text: string): string {
  const pad = "‌ ".repeat(60);
  return `<div style="display:none;max-height:0;overflow:hidden;opacity:0;color:transparent;height:0;width:0;mso-hide:all">${escapeHtml(text)}${pad}</div>`;
}

/** Minimal HTML-escape for interpolating console-controlled text into the shell. */
export function escapeHtml(value: string): string {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

/**
 * A bulletproof, gradient call-to-action button. Table-based with a
 * `background-color` fallback under the gradient so Gmail/Outlook (which drop
 * `background-image`) still render a solid indigo pill. `href` is
 * console-generated (an enrollment or launch URL); callers pass a trusted value.
 */
export function ctaButton(href: string, label: string): string {
  return [
    `<table role="presentation" cellpadding="0" cellspacing="0" border="0" style="margin:0 auto"><tr>`,
    `<td align="center" style="border-radius:12px;background-color:${BRAND.indigo};background-image:linear-gradient(135deg,#6366f1 0%,#4f46e5 55%,#4338ca 100%)">`,
    `<a href="${href}" target="_blank" style="display:inline-block;padding:15px 40px;font-family:${BRAND.fontStack};font-size:15px;font-weight:600;line-height:1;color:#ffffff;text-decoration:none;border-radius:12px;letter-spacing:.2px">${escapeHtml(label)}</a>`,
    `</td></tr></table>`,
  ].join("");
}

/**
 * Wrap an email body fragment in the premium branded shell: a soft page backdrop,
 * a centered white card (max 560px) with a rounded logo-badge header, a thin brand
 * gradient rule, the content, and a muted footer. TABLE-based with inline styles
 * only — Gmail/Outlook strip `<style>`, flexbox, and grid — so it renders the same
 * across clients and stays mobile-safe. Callers pair this with {@link logoAttachment}
 * so the `cid:` logo resolves, and pass a short `preview` for the inbox snippet.
 */
export function brandedEmailHtml(innerHtml: string, opts: { preview?: string } = {}): string {
  return [
    opts.preview ? preheader(opts.preview) : "",
    `<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="width:100%;border-collapse:collapse;background-color:${BRAND.page};margin:0;padding:0">`,
    `<tr><td align="center" style="padding:36px 12px">`,
    // Card
    `<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="560" style="width:100%;max-width:560px;border-collapse:separate;background-color:${BRAND.card};border:1px solid ${BRAND.border};border-radius:18px;overflow:hidden;box-shadow:0 1px 3px rgba(15,23,42,.06)">`,
    // Header: logo badge + wordmark
    `<tr><td align="center" style="padding:36px 40px 22px 40px">`,
    `<img src="cid:${INFRAWEAVER_LOGO_CID}" width="64" height="64" alt="InfraWeaver" style="display:block;margin:0 auto 14px auto;border:0;border-radius:16px"/>`,
    `<div style="font-family:${BRAND.fontStack};font-size:19px;font-weight:700;letter-spacing:-.2px;color:${BRAND.ink}">InfraWeaver</div>`,
    `</td></tr>`,
    // Brand gradient rule
    `<tr><td style="padding:0 40px"><div style="height:3px;border-radius:3px;background-color:${BRAND.indigo};background-image:linear-gradient(90deg,#6366f1,#7c3aed,#4338ca)"></div></td></tr>`,
    // Body
    `<tr><td style="padding:28px 40px 8px 40px;font-family:${BRAND.fontStack};font-size:15px;line-height:1.65;color:${BRAND.ink}">${innerHtml}</td></tr>`,
    // Footer
    `<tr><td style="padding:22px 40px 30px 40px">`,
    `<div style="height:1px;background-color:${BRAND.border};margin:0 0 16px 0"></div>`,
    `<div style="font-family:${BRAND.fontStack};font-size:12px;line-height:1.6;color:${BRAND.faint}">InfraWeaver &middot; automated platform access. This is a transactional message; please do not reply.</div>`,
    `</td></tr>`,
    `</table>`,
    `</td></tr></table>`,
  ].join("");
}
